function execute(address t, uint256 v, bytes memory d) external returns (bytes memory r) {
    require(msg.sender == entryPoint() || msg.sender == owner());
    (bool s, bytes memory ret) = t.call{value: v}(d);
    if (!s) { assembly { revert(add(ret, 32), mload(ret)) } }
    return ret;
}
function delegateExecute(address d, bytes memory data) external returns (bytes memory) {
    require(msg.sender == owner());
    (bool s, bytes memory r) = d.delegatecall(data);
    require(s);
    return r;
}

