    public payable virtual onlyEntryPointOrOwner returns (bytes memory result)
{
    assembly {
        result := mload(0x40)
        calldatacopy(result, data.offset, data.length)
        if iszero(call(gas(), target, value, result, data.length, codesize(), 0)) {
            returndatacopy(result, 0, returndatasize())
